        reader.onload = function (e) {
            $('#img_id').attr('src', e.target.result);
        }

        reader.readAsDataURL(input.files[0]);
    }
  }
</script>
`

Would I be able to get guidance on changing the displayed photo from the facebook image to user uploaded image, and for saving the user uploaded image?

